#!/usr/bin/env python3
"""Build the representative-field QA workbench as a self-contained HTML file."""
from __future__ import annotations

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[0]
PROJECT = ROOT.parent
SOURCE = PROJECT / "html" / "data" / "cases.json"
COMPARISON_SOURCE = PROJECT / "html" / "data" / "comparison_results.json"
OUTPUT = PROJECT / "html" / "qa_v0.1.html"


def main() -> None:
    data = json.loads(SOURCE.read_text(encoding="utf-8"))
    comparison = {"datasets": [], "rows": []}
    if COMPARISON_SOURCE.exists():
        comparison = json.loads(COMPARISON_SOURCE.read_text(encoding="utf-8-sig"))
    payload = json.dumps(data, ensure_ascii=False, separators=(",", ":")).replace("</", "<\\/")
    comparison_payload = json.dumps(comparison, ensure_ascii=False, separators=(",", ":")).replace("</", "<\\/")
    html = TEMPLATE.replace("__DATA__", payload).replace("__COMPARISON__", comparison_payload)
    OUTPUT.write_text(html, encoding="utf-8", newline="\n")
    print(f"wrote {OUTPUT} ({len(data)} cases, {OUTPUT.stat().st_size:,} bytes)")


TEMPLATE = r'''<!doctype html>
<html lang="ja">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>代表項目QA v0.1｜大規模成長投資補助金</title>
<style>
:root{--ink:#172033;--muted:#667085;--line:#d9dee8;--paper:#fff;--bg:#f2f4f8;--nav:#14213d;--blue:#2155a3;--good:#147d64;--warn:#a85f00;--bad:#b42318;--partial:#7158a6;--na:#667085;--rail:314px;--pdf:42vw}
*{box-sizing:border-box}html,body{height:100%;margin:0;font-family:system-ui,-apple-system,"Segoe UI","Noto Sans JP",sans-serif;color:var(--ink);background:var(--bg)}button,input,select{font:inherit}
.top{height:64px;display:flex;align-items:center;gap:10px;padding:9px 14px;background:var(--nav);color:white;position:sticky;top:0;z-index:20}.top h1{font-size:16px;margin:0 12px 0 0;white-space:nowrap}.top button,.top select,.top input{height:38px;border:1px solid #667085;border-radius:7px;background:white;color:#172033;padding:0 10px}.top input{width:min(330px,25vw)}.top .grow{flex:1}.count{font-size:12px;color:#d9e1f2;white-space:nowrap}
.layout{display:grid;grid-template-columns:var(--rail) minmax(570px,1fr) minmax(440px,var(--pdf));height:calc(100vh - 64px);transition:grid-template-columns .18s ease}.layout.rail-closed{grid-template-columns:0 minmax(570px,1fr) minmax(440px,var(--pdf))}.rail{overflow:hidden;border-right:1px solid var(--line);background:#fff;min-width:0}.rail-inner{width:var(--rail);height:100%;display:flex;flex-direction:column}.rail-head{padding:12px;border-bottom:1px solid var(--line);display:grid;gap:8px}.rail-list{overflow:auto;padding:8px}.case{width:100%;text-align:left;border:1px solid transparent;border-radius:8px;background:transparent;padding:9px 10px;margin:0 0 4px;cursor:pointer}.case:hover{background:#f3f6fb}.case.active{background:#eaf1fc;border-color:#9db8df}.case .name{font-weight:700;font-size:14px}.case .meta{font-size:11px;color:var(--muted);margin-top:3px;display:flex;justify-content:space-between}.case .danger{color:var(--bad);font-weight:700}
.main{overflow:auto;padding:18px 20px 70px}.pdf{border-left:1px solid var(--line);background:#e7eaf0;display:flex;flex-direction:column;min-width:0}.pdfbar{height:48px;background:#fff;border-bottom:1px solid var(--line);display:flex;align-items:center;gap:8px;padding:7px 10px}.pdfbar a,.pdfbar button{font-size:12px}.pdf iframe{border:0;width:100%;height:100%;background:white}.pdfnote{padding:20px;color:var(--muted);background:white;line-height:1.7}
.casehead{background:linear-gradient(115deg,#172b4d,#235899);color:white;border-radius:12px;padding:18px 20px;margin-bottom:14px}.casehead h2{margin:0 0 5px;font-size:24px}.casehead .sub{display:flex;gap:14px;flex-wrap:wrap;color:#dce8fa;font-size:13px}.casehead a{color:white}
.attention{border:1px solid #f2c8c3;background:#fff7f6;border-radius:10px;padding:14px;margin-bottom:14px}.attention.ok{border-color:#b9dfd5;background:#f4fbf8}.attention h3{font-size:15px;margin:0 0 8px}.attention ul{margin:0;padding-left:20px}.attention li{margin:4px 0;font-size:13px}.legend{display:flex;gap:6px;flex-wrap:wrap;margin-top:10px;font-size:11px}
.section{background:var(--paper);border:1px solid var(--line);border-radius:10px;margin:0 0 14px;overflow:hidden}.section h3{font-size:16px;margin:0;padding:12px 15px;border-bottom:1px solid var(--line);background:#f8fafc}.body{padding:14px}.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}.kv{border:1px solid #e5e9f0;border-radius:8px;padding:9px 10px;min-height:66px}.kv .k{font-size:11px;color:var(--muted);margin-bottom:4px}.kv .v{font-size:15px;font-weight:700;white-space:pre-wrap;overflow-wrap:anywhere}.kv .raw{font-size:11px;color:var(--muted);margin-top:4px}.wide{grid-column:1/-1}.metric-head{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:10px}.metric-head h4{margin:0;font-size:16px}.badge{display:inline-flex;align-items:center;border-radius:999px;padding:3px 8px;font-size:11px;font-weight:700;border:1px solid currentColor;white-space:nowrap}.ready{color:var(--good);background:#edf9f5}.usable_with_caution{color:var(--warn);background:#fff8e8}.partial{color:var(--partial);background:#f6f2ff}.review_required{color:var(--bad);background:#fff2f0}.unavailable{color:var(--na);background:#f2f4f7}.reason{font-size:12px;color:var(--muted);margin:6px 0 0;white-space:pre-wrap}.metric-table{width:100%;border-collapse:collapse;font-size:12px}.metric-table th,.metric-table td{border:1px solid var(--line);padding:7px;vertical-align:top}.metric-table th{background:#f6f8fb;text-align:left}.metric-table .value{font-weight:700;font-size:14px}.two-status{display:flex;gap:4px;flex-wrap:wrap}.textblock{white-space:pre-wrap;line-height:1.65;font-size:13px;max-height:280px;overflow:auto;background:#fbfcfe;border:1px solid #e7eaf0;border-radius:7px;padding:10px}.sourcebtn{border:1px solid #aab4c3;background:white;border-radius:6px;color:var(--blue);cursor:pointer;padding:4px 7px}.sourcebtn:hover{background:#edf3fc}.comparison-diff{border-color:#d92d20!important;background:#fff3f2!important;box-shadow:inset 4px 0 #d92d20}.comparison-missing{border-color:#f79009!important;background:#fffaeb!important}.case.comparison-problem{border-color:#d92d20;background:#fff3f2}.comp-pill{color:#b42318;font-weight:800}.comparison-section{border:2px solid #d92d20}.comparison-section h3{background:#fee4e2;color:#7a271a}.comparison-table{width:100%;border-collapse:collapse;font-size:11px;display:block;overflow:auto}.comparison-table th,.comparison-table td{border:1px solid var(--line);padding:7px;vertical-align:top;white-space:nowrap}.comparison-table th{background:#f8fafc}.comparison-table tr.diff{background:#fff1f0}.comparison-table tr.missing{background:#fff8e8}.comparison-table .different,.comparison-table .normalization_error,.comparison-table .record_ambiguous{color:#b42318;font-weight:800}.comparison-table .current_missing,.comparison-table .external_missing,.comparison-table .current_only,.comparison-table .external_only{color:#a15c00;font-weight:800}#comparisonRun.active{background:#b42318;color:#fff;border-color:#b42318}#comparisonFilter:disabled{opacity:.55}
details{border-top:1px solid var(--line)}details:first-child{border-top:0}summary{cursor:pointer;padding:11px 14px;font-weight:700}details>.detailbody{padding:0 14px 14px}.all-controls{display:flex;gap:8px;margin-bottom:8px}.all-controls input{border:1px solid var(--line);border-radius:6px;padding:7px;width:300px}.all-table{width:100%;border-collapse:collapse;font-size:11px}.all-table td{border-bottom:1px solid #edf0f4;padding:6px;vertical-align:top;overflow-wrap:anywhere}.all-table td:first-child{width:36%;font-weight:700;color:#475467}.empty{color:#98a2b3;font-style:italic}.mobile-pdf{display:none}
@media(max-width:1150px){.layout,.layout.rail-closed{grid-template-columns:var(--rail) minmax(0,1fr)}.layout.rail-closed{grid-template-columns:0 minmax(0,1fr)}.pdf{display:none}.mobile-pdf{display:inline-flex}.grid{grid-template-columns:repeat(2,minmax(0,1fr))}}
@media(max-width:720px){.top h1,.top select,.count{display:none}.top input{width:auto;min-width:0;flex:1}.layout,.layout.rail-closed{display:block;height:calc(100vh - 64px)}.rail{position:fixed;top:64px;bottom:0;left:0;z-index:15;width:var(--rail);box-shadow:3px 0 14px #0003;transition:transform .18s}.rail-closed .rail{transform:translateX(-100%)}.main{height:100%;padding:12px}.grid{grid-template-columns:1fr}.metric-table{display:block;overflow-x:auto}.casehead h2{font-size:20px}}
</style>
</head>
<body>
<header class="top">
  <button id="railToggle" aria-expanded="true" title="会社一覧を開閉">☰ 会社</button>
  <h1>代表項目QA <small>v0.1</small></h1>
  <input id="search" type="search" placeholder="企業名・case_id・本文を検索">
  <select id="roundFilter" aria-label="公募回"><option value="">全公募回</option></select>
  <select id="statusFilter" aria-label="信頼性"><option value="">全信頼性</option><option value="review_required">要確認あり</option><option value="usable_with_caution">注意あり</option><option value="ready">主要項目すべて利用可</option></select>
  <button id="comparisonRun">差分検証を開始</button>
  <select id="comparisonFilter" aria-label="外部比較" disabled><option value="">全比較状態</option><option value="problem">差異・欠損あり</option><option value="different">値の相違</option><option value="missing">片側欠損</option><option value="equal">全項目一致</option></select>
  <span class="grow"></span><span class="count" id="count"></span>
</header>
<div class="layout" id="layout">
 <aside class="rail"><div class="rail-inner">
  <div class="rail-head"><select id="sort"><option value="file">ファイル番号順</option><option value="company">会社名順</option></select><div class="legend"><span class="badge review_required">要確認</span><span class="badge usable_with_caution">注意</span><span class="badge ready">利用可</span></div></div>
  <div class="rail-list" id="caseList"></div>
 </div></aside>
 <main class="main" id="main"></main>
 <aside class="pdf"><div class="pdfbar"><strong>PDF照合</strong><button id="reloadPdf">ローカルPDF</button><a id="officialPdf" target="_blank" rel="noopener">公式PDF</a><span id="pdfPage"></span></div><iframe id="pdfFrame" title="原資料PDF"></iframe></aside>
</div>
<script>const DATA=__DATA__;const COMPARISON=__COMPARISON__;</script>
<script>
const STATUSES=['project_cost','subsidy','sales_values','sales_rate','labor_values','labor_rate','employee_pay_values','employee_pay_rate','officer_pay_values','officer_pay_rate','employees_values','employees_rate'];
const STATUS_LABEL={ready:'利用可',usable_with_caution:'注意して利用',partial:'一部のみ',review_required:'要原資料確認',unavailable:'値なし'};
const FIELD_LABEL={case_id:'案件ID',round:'公募回',company:'申請企業',target_entity:'対象企業',scope:'対象範囲',other_participants:'その他参加者',page_count:'総ページ数',vision_page_count:'長期ビジョン頁数',project_page_count:'補助事業頁数',additional_page_count:'追加頁数',project_cost_million_yen:'事業費（百万円）',subsidy_million_yen:'補助額（百万円）',subsidy_rate_pct:'補助率（%）',cost_page:'事業費の出典頁',investment_representative_basis:'投資額代表値の根拠',cost_source_method:'事業費抽出方法',cost_validation:'事業費検証',cost_box_transcription:'事業費Box原文',project_cost_value_raw:'事業費原値',project_cost_unit_raw:'事業費原単位',project_cost_million_yen_normalized:'事業費換算値（百万円）',subsidy_value_raw:'補助額原値',subsidy_unit_raw:'補助額原単位',subsidy_million_yen_normalized:'補助額換算値（百万円）',sales_baseline_period_label:'売上基準期間（原文）',sales_baseline_year_before_correction:'売上基準年（補正前）',sales_baseline_year_after_correction:'売上基準年（補正後）',sales_baseline_oku_yen:'売上基準値（億円）',sales_target_period_label:'売上目標期間（原文）',sales_target_year_before_correction:'売上目標年（補正前）',sales_target_year_after_correction:'売上目標年（補正後）',sales_target_oku_yen:'売上目標値（億円）',sales_increase_oku_yen_normalized:'売上増加額（億円）',sales_growth_pct:'売上成長率（%）',sales_cagr_pct:'売上CAGR（%）',sales_growth_rate_definition:'成長率の定義',sales_multiple:'売上倍率',sales_representative_scope:'売上代表系列の範囲',sales_representative_reason:'売上代表系列の選定理由',manual_audit_confidence:'目視監査の確度',manual_audit_correction_count:'目視監査の修正数',pdf_url:'公式PDF URL'};
const METRICS=[['labor','労働生産性'],['employee_pay','従業員1人あたり給与支給総額'],['officer_pay','役員1人あたり給与支給総額'],['employees','従業員数']];
const MAIN_STATUS=STATUSES;
let selected=location.hash.slice(1)||DATA[0]?.case_id||''; let filtered=[]; let pdfPage=1; let comparisonEnabled=false;
const COMP_ROWS=COMPARISON.rows||[],COMP_DATASETS=COMPARISON.datasets||[],COMP_SEVERE=new Set(['different','normalization_error','record_ambiguous']),COMP_MISSING=new Set(['current_missing','external_missing','current_only','external_only']);
const COMP_BY_CASE=new Map();COMP_ROWS.forEach(r=>{if(!r.case_id)return;if(!COMP_BY_CASE.has(r.case_id))COMP_BY_CASE.set(r.case_id,[]);COMP_BY_CASE.get(r.case_id).push(r)});
const $=s=>document.querySelector(s); const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const present=v=>!(v===null||v===undefined||v===''); const show=v=>present(v)?esc(v):'<span class="empty">記載なし</span>';
function badge(s,label=''){s=s||'unavailable';return `<span class="badge ${esc(s)}">${esc(label||STATUS_LABEL[s]||s)}</span>`}
function num(v,unit=''){return present(v)?`${esc(v)}${unit?` <small>${esc(unit)}</small>`:''}`:'<span class="empty">記載なし</span>'}
function compRows(id=selected){return COMP_BY_CASE.get(id)||[]}
function compState(id){const rs=compRows(id);if(rs.some(r=>COMP_SEVERE.has(r.status)))return'different';if(rs.some(r=>COMP_MISSING.has(r.status)))return'missing';if(rs.length&&rs.every(r=>['equal','within_tolerance','both_missing'].includes(r.status)))return'equal';return'none'}
function compProblems(id){return compRows(id).filter(r=>COMP_SEVERE.has(r.status)||COMP_MISSING.has(r.status))}
function compClass(fields){if(!comparisonEnabled)return'';const fs=new Set(Array.isArray(fields)?fields:[fields]);const rs=compRows().filter(r=>fs.has(r.field));return rs.some(r=>COMP_SEVERE.has(r.status))?'comparison-diff':rs.some(r=>COMP_MISSING.has(r.status))?'comparison-missing':''}
function kv(k,v,raw='',cls='',fields=''){return `<div class="kv ${cls} ${compClass(fields)}"><div class="k">${esc(k)}</div><div class="v">${v}</div>${raw?`<div class="raw">${raw}</div>`:''}</div>`}
function status(c,key){return c[`${key}_analysis_status`]||'unavailable'}
function reasons(c,key){return c[`${key}_analysis_reasons`]||''}
function naturalId(id){return String(id).split(/(\d+)/).map(x=>/^\d+$/.test(x)?Number(x):x.toLowerCase())}
function cmpNatural(a,b){const A=naturalId(a),B=naturalId(b);for(let i=0;i<Math.max(A.length,B.length);i++){if(A[i]===undefined)return -1;if(B[i]===undefined)return 1;if(A[i]===B[i])continue;if(typeof A[i]===typeof B[i])return A[i]<B[i]?-1:1;return typeof A[i]==='number'?-1:1}return 0}
function attention(c){return MAIN_STATUS.flatMap(k=>{const s=status(c,k);return ['review_required','usable_with_caution','partial'].includes(s)?[{k,s,r:reasons(c,k)}]:[]})}
function statusName(k){return ({project_cost:'事業費',subsidy:'補助額',sales_values:'売上高の値',sales_rate:'売上成長率',labor_values:'労働生産性の値',labor_rate:'労働生産性の率',employee_pay_values:'従業員給与の値',employee_pay_rate:'従業員給与の率',officer_pay_values:'役員給与の値',officer_pay_rate:'役員給与の率',employees_values:'従業員数の値',employees_rate:'従業員数の率'})[k]||k}
function sourceButton(page){return present(page)?`<button class="sourcebtn" onclick="openPdfPage(${Number(page)||1})">PDF ${esc(page)}頁</button>`:''}
function renderAttention(c){const a=attention(c);if(!a.length)return `<section class="attention ok"><h3>先に見る箇所</h3><div>主要な代表項目に「要原資料確認」「注意して利用」はありません。</div><div class="legend">${badge('ready')} 値と原資料の対応を確認済み　${badge('unavailable')} 原資料に値がない／代表値にできない</div></section>`;return `<section class="attention"><h3>先に見る箇所 — ${a.length}項目</h3><ul>${a.map(x=>`<li>${badge(x.s)} <strong>${esc(statusName(x.k))}</strong>${x.r?`：${esc(x.r)}`:''}</li>`).join('')}</ul><div class="legend">赤は分析投入前にPDF確認、黄は条件を理解して利用、紫は値の一部のみ利用可能です。</div></section>`}
function renderStructure(c){return `<section class="section"><h3>1. 案件構造</h3><div class="body grid">${kv('申請企業',show(c.company))}${kv('対象企業',show(c.target_entity))}${kv('対象範囲',show(c.scope))}${kv('公募回',show(c.round))}${kv('コンソーシアム',c.has_consortium?'あり':'なし',present(c.consortium_member_count)?`構成員数 ${esc(c.consortium_member_count)}`:'')}${kv('投資案件',c.has_multiple_investments?'複数案件':'単一／不明',present(c.investment_component_count)?`${esc(c.investment_component_count)}件（${esc(c.investment_component_count_method||'')}）`:'')}${kv('親会社・子会社・関連会社',`${c.has_parent_company_reference?'親会社あり':'—'} / ${c.has_subsidiary_reference?'子会社あり':'—'} / ${c.has_related_company_reference?'関連会社あり':'—'}`,'','wide')}${kv('その他参加者',show(c.other_participants),'','wide')}${kv('ページ構成',`${show(c.page_count)}頁`, `長期ビジョン ${show(c.vision_page_count)} / 補助事業 ${show(c.project_page_count)} / 追加 ${show(c.additional_page_count)}`,'wide')}</div></section>`}
function renderMoney(c){return `<section class="section"><h3>2. 投資額・補助額</h3><div class="body"><div class="metric-head"><h4>申請全体の代表額</h4>${badge(status(c,'project_cost'),'事業費 '+(STATUS_LABEL[status(c,'project_cost')]||''))}${badge(status(c,'subsidy'),'補助額 '+(STATUS_LABEL[status(c,'subsidy')]||''))}${sourceButton(c.cost_page)}</div><div class="grid">${kv('事業費（換算代表値）',num(c.project_cost_million_yen_normalized??c.project_cost_million_yen,'百万円'),`原記載 ${show(c.project_cost_value_raw)} ${show(c.project_cost_unit_raw)}`,'',['project_cost_million_yen','project_cost_million_yen_normalized'])}${kv('補助額（換算代表値）',num(c.subsidy_million_yen_normalized??c.subsidy_million_yen,'百万円'),`原記載 ${show(c.subsidy_value_raw)} ${show(c.subsidy_unit_raw)}`,'',['subsidy_million_yen','subsidy_million_yen_normalized'])}${kv('補助率',num(c.subsidy_rate_pct,'%'),'','',['subsidy_rate_pct'])}${kv('代表値の根拠',show(c.investment_representative_basis),'','wide',['investment_representative_basis'])}</div><p class="reason"><b>事業費：</b>${show(reasons(c,'project_cost'))}　<b>補助額：</b>${show(reasons(c,'subsidy'))}</p>${c.cost_box_transcription?`<details><summary>事業費・補助額のBox原文</summary><div class="detailbody textblock">${esc(c.cost_box_transcription)}</div></details>`:''}</div></section>`}
function renderSales(c){const vs=status(c,'sales_values'),rs=status(c,'sales_rate');return `<section class="section"><h3>3. 売上成長目標</h3><div class="body"><div class="metric-head"><h4>申請企業の代表系列</h4>${badge(vs,'値 '+(STATUS_LABEL[vs]||''))}${badge(rs,'率 '+(STATUS_LABEL[rs]||''))}</div><div class="grid">${kv('代表系列・範囲',show(c.sales_representative_scope),show(c.sales_representative_series_id),'',['sales_representative_scope'])}${kv('基準年度',show(c.sales_baseline_year_after_correction??c.sales_baseline_year),`原文 ${show(c.sales_baseline_period_label)} / 補正前 ${show(c.sales_baseline_year_before_correction)}`,'',['sales_baseline_year','sales_baseline_year_after_correction'])}${kv('基準売上高',num(c.sales_baseline_oku_yen,'億円'),'','',['sales_baseline_oku_yen'])}${kv('目標年度',show(c.sales_target_year_after_correction??c.sales_target_year),`原文 ${show(c.sales_target_period_label)} / 補正前 ${show(c.sales_target_year_before_correction)}`,'',['sales_target_year','sales_target_year_after_correction'])}${kv('目標売上高',num(c.sales_target_oku_yen,'億円'),'','',['sales_target_oku_yen'])}${kv('売上増加額',num(c.sales_increase_oku_yen_normalized??c.sales_increase_oku_yen,'億円'),`原記載 ${show(c.sales_increase_value_raw)} ${show(c.sales_increase_unit_raw)}`,'',['sales_increase_oku_yen','sales_increase_oku_yen_normalized'])}${kv('成長率',num(c.sales_growth_pct,'%'),show(c.sales_growth_rate_definition),'',['sales_growth_pct'])}${kv('年平均成長率（CAGR）',num(c.sales_cagr_pct,'%'),'','',['sales_cagr_pct'])}${kv('倍率',num(c.sales_multiple,'倍'),'','',['sales_multiple'])}${kv('代表系列の選定理由',show(c.sales_representative_reason),'','wide',['sales_representative_reason'])}</div><p class="reason"><b>値：</b>${show(reasons(c,'sales_values'))}　<b>率：</b>${show(reasons(c,'sales_rate'))}</p>${c.has_multiple_sales_series?`<details><summary>複数の売上系列（${show(c.sales_series_count)}系列）</summary><div class="detailbody"><div class="textblock">${esc(JSON.stringify(c.sales_series||[],null,2))}</div></div></details>`:''}</div></section>`}
function metricRow(c,p,label){const vs=status(c,p+'_values'),rs=status(c,p+'_rate');const bval=c[p+'_base_value_man_yen_per_person']??c[p+'_base_value'];const tval=c[p+'_target_value_man_yen_per_person']??c[p+'_target_value'];const unit=c[p+'_normalized_unit']||c[p+'_unit']||'';const fields=[p+'_base_year',p+'_base_year_after_correction',p+'_base_value',p+'_base_value_man_yen_per_person',p+'_target_year',p+'_target_year_after_correction',p+'_target_value',p+'_target_value_man_yen_per_person',p+'_annual_rate_pct'];return `<tr class="${compClass(fields)}"><th>${esc(label)}<div class="two-status">${badge(vs,'値 '+(STATUS_LABEL[vs]||''))}${badge(rs,'率 '+(STATUS_LABEL[rs]||''))}</div></th><td><span class="value">${show(c[p+'_base_year_after_correction']??c[p+'_base_year'])}</span><br><small>原文 ${show(c[p+'_base_period_label'])}<br>補正前 ${show(c[p+'_base_year_before_correction'])}</small></td><td><span class="value">${num(bval,unit)}</span><br><small>原値 ${show(c[p+'_base_value_raw'])} ${show(c[p+'_unit_raw'])}</small></td><td><span class="value">${show(c[p+'_target_year_after_correction']??c[p+'_target_year'])}</span><br><small>原文 ${show(c[p+'_target_period_label'])}<br>補正前 ${show(c[p+'_target_year_before_correction'])}</small></td><td><span class="value">${num(tval,unit)}</span><br><small>原値 ${show(c[p+'_target_value_raw'])} ${show(c[p+'_unit_raw'])}</small></td><td><span class="value">${num(c[p+'_annual_rate_pct'],'%')}</span></td><td>${show(reasons(c,p+'_values'))}<br>${show(reasons(c,p+'_rate'))}<br><small>${show(c[p+'_validation'])}</small></td></tr>`}
function renderMetrics(c){return `<section class="section"><h3>4. 主要4指標</h3><div class="body"><table class="metric-table"><thead><tr><th>指標・信頼性</th><th>基準時点</th><th>基準値</th><th>目標時点</th><th>目標値</th><th>年平均率</th><th>注意理由・検証</th></tr></thead><tbody>${METRICS.map(m=>metricRow(c,...m)).join('')}</tbody></table><details><summary>主要指標の抽出根拠テキスト</summary><div class="detailbody">${METRICS.map(([p,l])=>`<h4>${esc(l)}</h4><div class="textblock">${show(c[p+'_raw_evidence'])}</div>`).join('')}</div></details></div></section>`}
function renderNarratives(c){const box=(title,v)=>v?`<details><summary>${esc(title)}</summary><div class="detailbody textblock">${esc(v)}</div></details>`:'';return `<section class="section"><h3>5. Box文章・原文</h3>${box('長期成長ビジョン',c.vision)}${box('外発的動機',c.external_motivation)}${box('内発的動機',c.internal_motivation)}${box('当社の概要',c.company_overview)}${box('その他のBox',typeof c.other_boxes==='string'?c.other_boxes:JSON.stringify(c.other_boxes||[],null,2))}${box('全Box構造（監査用）',JSON.stringify(c.boxes||[],null,2))}</section>`}
function renderAllFields(c){const keys=Object.keys(c).filter(k=>!['boxes','sales_series','metrics','quality_flags'].includes(k)).sort((a,b)=>a.localeCompare(b));return `<section class="section"><h3>6. cases.csv 全代表列・補助列</h3><div class="body"><p class="reason">主画面で整理した代表項目を含め、CSV由来の全スカラー列を欠落なく表示します。列名検索で定義・値を確認できます。</p><div class="all-controls"><input id="fieldSearch" placeholder="列名・値を絞り込み"><span>${keys.length}列</span></div><table class="all-table" id="allTable"><tbody>${keys.map(k=>`<tr class="${compClass(k)}" data-text="${esc((k+' '+String(c[k]??'')).toLowerCase())}"><td>${esc(k)}<br><small>${esc(FIELD_LABEL[k]||'')}</small></td><td>${typeof c[k]==='object'?`<pre>${esc(JSON.stringify(c[k],null,2))}</pre>`:show(c[k])}</td></tr>`).join('')}</tbody></table></div></section>`}
function renderComparison(c){if(!comparisonEnabled)return'';const rows=compRows(c.case_id),labels={equal:'一致',within_tolerance:'許容差内',both_missing:'双方空欄',different:'相違',current_missing:'cases.csv欠損',external_missing:'比較データ欠損',normalization_error:'正規化エラー',record_ambiguous:'照合候補複数',current_only:'比較レコードなし',external_only:'cases.csvレコードなし'};if(!rows.length)return `<section class="section"><h3>外部抽出データとの差分</h3><div class="body empty">この案件に対応する比較レコードはありません。</div></section>`;const problems=compProblems(c.case_id).length;return `<section class="section ${problems?'comparison-section':''}"><h3>外部抽出データとの差分 — ${problems}件</h3><div class="body"><p class="reason">比較元：${esc([...new Set(rows.map(r=>r.dataset_label))].join(' / '))}　<a href="../data/processed/comparison_results.csv">比較結果CSV</a></p><table class="comparison-table"><thead><tr><th>項目</th><th>cases.csv</th><th>比較データ</th><th>正規化後（現行 / 比較）</th><th>差</th><th>判定</th></tr></thead><tbody>${rows.map(r=>{const cls=COMP_SEVERE.has(r.status)?'diff':COMP_MISSING.has(r.status)?'missing':'';const units=(r.rule?.current_unit||r.rule?.external_unit)?`<br><small>単位 ${esc(r.rule?.current_unit||'—')} ← ${esc(r.rule?.external_unit||'—')}${r.rule?.conversion_note?' / '+esc(r.rule.conversion_note):''}</small>`:'';return `<tr class="${cls}"><td><b>${esc(r.field_label||r.field)}</b><br><small>${esc(r.field)} ← ${esc(r.external_column||'')}</small>${units}</td><td>${show(r.current_raw)}</td><td>${show(r.external_raw)}</td><td>${show(r.current_normalized)} / ${show(r.external_normalized)}</td><td>${show(r.difference)}</td><td class="${esc(r.status)}">${esc(labels[r.status]||r.status)}${r.message?'<br><small>'+esc(r.message)+'</small>':''}</td></tr>`}).join('')}</tbody></table></div></section>`}
function render(c){if(!c)return; const official=esc(c.pdf_url||''); $('#main').innerHTML=`<header class="casehead"><h2>${esc(c.company)}</h2><div class="sub"><span>${esc(c.case_id)}</span><span>${esc(c.round)}</span><span>${esc(c.target_entity||'')}</span><a href="${official}" target="_blank" rel="noopener">公式PDFを開く</a><button class="sourcebtn mobile-pdf" onclick="window.open('${official}','_blank')">PDF</button></div></header>${renderAttention(c)}${renderComparison(c)}${renderStructure(c)}${renderMoney(c)}${renderSales(c)}${renderMetrics(c)}${renderNarratives(c)}${renderAllFields(c)}`; $('#fieldSearch')?.addEventListener('input',e=>{const q=e.target.value.toLowerCase();document.querySelectorAll('#allTable tr').forEach(tr=>tr.hidden=!tr.dataset.text.includes(q))}); setPdf(c); document.title=`${c.company}｜代表項目QA v0.1`;}
function setPdf(c,page=1){pdfPage=page||1;const local=c.local_pdf||`../local_assets/pdfs/${c.case_id}.pdf`;$('#pdfFrame').src=`${local}#page=${pdfPage}&view=FitH`;$('#officialPdf').href=c.pdf_url||'#';$('#pdfPage').textContent=`${pdfPage}頁`}
window.openPdfPage=function(page){const c=DATA.find(x=>x.case_id===selected);if(c){setPdf(c,page);document.querySelector('.pdf')?.scrollIntoView({behavior:'smooth'})}}
function matchesStatus(c,f){if(!f)return true;if(f==='ready')return MAIN_STATUS.every(k=>['ready','unavailable'].includes(status(c,k)));return MAIN_STATUS.some(k=>status(c,k)===f)}
function apply(){const terms=$('#search').value.trim().toLowerCase().split(/\s+/).filter(Boolean),r=$('#roundFilter').value,s=$('#statusFilter').value,cf=comparisonEnabled?$('#comparisonFilter').value:'';filtered=DATA.filter(c=>{const hay=[c.company,c.case_id,c.round,c.target_entity,c.scope,c.vision,c.external_motivation,c.internal_motivation,c.cost_box_transcription,c.sales_representative_reason].map(v=>String(v??'').toLowerCase()).join('\n'),cs=compState(c.case_id),cm=!cf||(cf==='problem'&&['different','missing'].includes(cs))||cf===cs;return (!r||String(c.round)===r)&&matchesStatus(c,s)&&terms.every(q=>hay.includes(q))&&cm});const sort=$('#sort').value;filtered.sort((a,b)=>sort==='company'?String(a.company).localeCompare(String(b.company),'ja'):cmpNatural(a.case_id,b.case_id));const diffCases=comparisonEnabled?DATA.filter(c=>['different','missing'].includes(compState(c.case_id))).length:0;$('#count').textContent=`${filtered.length} / ${DATA.length}件${comparisonEnabled?'・外部差異 '+diffCases+'社':''}`;$('#caseList').innerHTML=filtered.map(c=>{const n=attention(c).filter(x=>x.s==='review_required').length,cp=comparisonEnabled?compProblems(c.case_id).length:0;return `<button class="case ${c.case_id===selected?'active':''} ${cp?'comparison-problem':''}" data-id="${esc(c.case_id)}"><div class="name">${esc(c.company)}</div><div class="meta"><span>${esc(c.case_id)}・${esc(c.round)}</span><span>${cp?`<b class="comp-pill">外部差異 ${cp}</b>`:n?`<span class="danger">要確認 ${n}</span>`:'—'}</span></div></button>`}).join('');document.querySelectorAll('.case').forEach(b=>b.onclick=()=>select(b.dataset.id));if(!filtered.some(c=>c.case_id===selected)&&filtered[0])select(filtered[0].case_id,false);else render(DATA.find(x=>x.case_id===selected))}
function select(id,scroll=true){selected=id;location.hash=id;document.querySelectorAll('.case').forEach(x=>x.classList.toggle('active',x.dataset.id===id));render(DATA.find(x=>x.case_id===id));if(scroll)$('#main').scrollTop=0}
function toggleRail(force){const closed=force??!$('#layout').classList.contains('rail-closed');$('#layout').classList.toggle('rail-closed',closed);$('#railToggle').setAttribute('aria-expanded',String(!closed));localStorage.setItem('qa_v01_rail_closed',closed?'1':'0')}
const rounds=[...new Set(DATA.map(c=>String(c.round)))].sort();$('#roundFilter').innerHTML+=[...rounds].map(r=>`<option value="${esc(r)}">${esc(r)}</option>`).join('');['search','roundFilter','statusFilter','sort','comparisonFilter'].forEach(id=>$('#'+id).addEventListener(id==='search'?'input':'change',apply));$('#railToggle').onclick=()=>toggleRail();$('#reloadPdf').onclick=()=>setPdf(DATA.find(x=>x.case_id===selected),pdfPage);const compRun=$('#comparisonRun');compRun.disabled=!COMP_ROWS.length;compRun.textContent=COMP_ROWS.length?'差分検証を開始':'比較データなし';compRun.onclick=()=>{comparisonEnabled=!comparisonEnabled;compRun.classList.toggle('active',comparisonEnabled);compRun.textContent=comparisonEnabled?'差分検証を終了':'差分検証を開始';$('#comparisonFilter').disabled=!comparisonEnabled;if(!comparisonEnabled)$('#comparisonFilter').value='';apply()};if(localStorage.getItem('qa_v01_rail_closed')==='1')toggleRail(true);apply();select(selected,false);
</script>
</body></html>'''


if __name__ == "__main__":
    main()
